// Define a function that takes an operation and two numbers as input
function calculate(operation: string, num1: number, num2: number): string {
    // Perform the operation based on the input
    switch (operation) {
        case 'add':
            return num1 + num2;
        case 'subtract':
            return num1 - num2;
        case 'multiply':
            return num1 * num2;
        case 'divide':
            if (num2 === 0) {
                return 'Error: Division by zero';
            }
            return num1 / num2;
        default:
            return 'Invalid operation';
    }
}
